{
  "name": "lab-result-notifier",
  "description": "Monitors lab results and sends alerts for critical values",
  "capabilities": ["db.read", "notification.send"],
  "constraints": {
    "readOnly": true,
    "alertThresholds": {
      "potassium": {"critical_high": 6.0, "critical_low": 2.5},
      "glucose": {"critical_high": 500, "critical_low": 40},
      "hemoglobin": {"critical_low": 7.0}
    },
    "notificationTargets": ["ordering_provider", "charge_nurse"],
    "auditLogging": true,
    "maxAlertsPerHour": 50,
    "suppressDuplicateWindow": "30m"
  }
}

