    "fileTypes": ["package.json", "package-lock.json", "go.mod", "go.sum", "requirements.txt", "Gemfile.lock", "pom.xml", "Cargo.lock"],
    "vulnerabilityDatabases": ["nvd", "github_advisory", "osv"],
    "licensePolicy": {
      "allowed": ["MIT", "Apache-2.0", "BSD-2-Clause", "BSD-3-Clause", "ISC"],
      "flagged": ["GPL-2.0", "GPL-3.0", "AGPL-3.0"],
      "banned": ["SSPL", "BSL"]
    },
    "autoFixDisabled": true,
    "reportFormat": "sarif"
